module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] temp;
    integer i;

    always @(*) begin
        temp = 0;
        for (i = 0; i < 8; i = i + 1) begin
            if (B[i])
                temp = temp + (A << i);
        end
        product = temp;
    end

endmodule
